class Stack:
    def __init__(self):
        self.items = []

    def is_empty(self):
        return len(self.items) == 0

    def push(self, item):
        self.items.append(item)

    def pop(self):
        if self.is_empty():
            raise IndexError("Pop from empty stack")
        return self.items.pop()

    def peek(self):
        if self.is_empty():
            raise IndexError("Peek from empty stack")
        return self.items[-1]

    def size(self):
        return len(self.items)

# Demonstration
stack = Stack()
stack.push(10)
stack.push(20)
stack.push(30)
print(f"Stack size: {stack.size()}")
print(f"Top element: {stack.peek()}")
print(f"Popped: {stack.pop()}")
print(f"Popped: {stack.pop()}")
print(f"Is empty: {stack.is_empty()}")

class Stack:
    def __init__(self):
        self.items = []

    def is_empty(self):
        return len(self.items) == 0

    def push(self, item):
        self.items.append(item)

    def pop(self):
        if self.is_empty():
            return None
        return self.items.pop()

    def peek(self):
        if self.is_empty():
            return None
        return self.items[-1]

def is_balanced(expression):
    stack = Stack()
    opening = {'(', '[', '{'}
    closing = {')': '(', ']': '[', '}': '{'}

    for char in expression:
        if char in opening:
            stack.push(char)
        elif char in closing:
            top = stack.pop()
            if top != closing[char]:
                return False

    return stack.is_empty()

# Test cases
test_cases = [
    "(a + b)",
    "((a + b)",
    "{[()]}",
    "{[(])}",
    "((((()))))",
    "(a + b) * (c - d)",
    "if (x > 0) { for (i=0; i<10; i++) { arr[i] = i; } }",
    "({[]})"
]

print("Balanced Parentheses Checker\n" + "="*40)
for expr in test_cases:
    result = is_balanced(expr)
    status = "✓ Balanced" if result else "✗ Unbalanced"
    print(f"{expr:45} -> {status}")
